101	static std::vector<at::Tensor> sparse_attn_prefill_interface(
102	    const at::Tensor &q,
103	    const at::Tensor &kv,
104	    const at::Tensor &indices,
105	    float sm_scale,
106	    int d_v,
107	    const std::optional<at::Tensor> &attn_sink,
108	    const std::optional<at::Tensor> &topk_length
109	) {
110	    using bf16 = cutlass::bfloat16_t;
111	    
112	    Arch arch = Arch();
113	    bool is_sm90a = arch.is_sm90a();
114	    bool is_sm100f = arch.is_sm100f();
115	    TORCH_CHECK(is_sm90a || is_sm100f, "Sparse Attention Forward Kernel is only supported on SM90a and SM100f architectures.");
116	
117	    KU_CHECK_NDIM(q, 3);
118	    KU_CHECK_NDIM(kv, 3);
119	    KU_CHECK_NDIM(indices, 3);
120	    KU_CHECK_NDIM(attn_sink, 1);
121	    KU_CHECK_NDIM(topk_length, 1);
122	
123	    int s_q = q.size(0);
124	    int s_kv = kv.size(0);
125	    int h_q = q.size(1);
126	    int h_kv = kv.size(1);
127	    int d_qk = q.size(2);
128	    int topk = indices.size(2);
129	    bool have_topk_length = topk_length.has_value();
130	
131	    TORCH_CHECK(d_qk == 576 || d_qk == 512, "Invalid d_qk: ", d_qk);
132	    TORCH_CHECK(d_v == 512, "Invalid d_v", d_v);
133	    
134	    KU_CHECK_DEVICE(q);
135	    KU_CHECK_DEVICE(kv);
136	    KU_CHECK_DEVICE(indices);
137	    KU_CHECK_DEVICE(attn_sink);
138	    KU_CHECK_DEVICE(topk_length);
139	    
140	    KU_CHECK_DTYPE(q, torch::kBFloat16);
141	    KU_CHECK_DTYPE(kv, torch::kBFloat16);
142	    KU_CHECK_DTYPE(indices, torch::kInt32);
143	    KU_CHECK_DTYPE(attn_sink, torch::kFloat32);
144	    KU_CHECK_DTYPE(topk_length, torch::kInt32);
145	    
146	    KU_CHECK_SHAPE(q, s_q, h_q, d_qk);
147	    KU_CHECK_SHAPE(kv, s_kv, h_kv, d_qk);
148	    KU_CHECK_SHAPE(indices, s_q, h_kv, topk);
149	    KU_CHECK_SHAPE(attn_sink, h_q);
150	    KU_CHECK_SHAPE(topk_length, s_q);
151	    
152	    KU_CHECK_LAST_DIM_CONTIGUOUS(q);
153	    KU_CHECK_LAST_DIM_CONTIGUOUS(kv);
154	    KU_CHECK_LAST_DIM_CONTIGUOUS(indices);
155	    KU_CHECK_LAST_DIM_CONTIGUOUS(attn_sink);
156	    KU_CHECK_LAST_DIM_CONTIGUOUS(topk_length);
157	    
158	    // Allocate results and buffers
159	    at::cuda::CUDAGuard device_guard{(char)q.get_device()};
160	    auto opts = q.options();
161	    
162	    at::Tensor out = torch::empty({s_q, h_q, d_v}, opts);
163	    at::Tensor lse = torch::empty({s_q, h_q}, opts.dtype(torch::kFloat));
164	    at::Tensor max_logits = torch::empty({s_q, h_q}, opts.dtype(torch::kFloat));
165	    KU_CHECK_CONTIGUOUS(out);
166	    KU_CHECK_CONTIGUOUS(lse);
167	    KU_CHECK_CONTIGUOUS(max_logits);
168	
169	    SparseAttnFwdParams params = {
170	        s_q, s_kv, h_q, h_kv, d_qk, d_v, topk,
171	        sm_scale, sm_scale * LOG_2_E,
172	
173	        (bf16*)q.data_ptr(),
174	        (bf16*)kv.data_ptr(),
175	        (int*)indices.data_ptr(),
176	        ku::get_optional_tensor_ptr<float>(attn_sink),
177	        ku::get_optional_tensor_ptr<int>(topk_length),
178	
179	        int64_stride_to_int(q.stride(0)), int64_stride_to_int(q.stride(1)),
180	        int64_stride_to_int(kv.stride(0)), int64_stride_to_int(kv.stride(1)),
181	        int64_stride_to_int(indices.stride(0)), int64_stride_to_int(indices.stride(1)),
182	
183	        (bf16*)out.data_ptr(),
184	        (float*)max_logits.data_ptr(),
185	        (float*)lse.data_ptr(),
186	
187	        arch.num_sms,
188	        at::cuda::getCurrentCUDAStream().stream()
189	    };
190	
191	    std::vector<FwdFeatures> required_features;
192	    if (h_q == 64) {
193	        required_features.push_back(FwdFeatures::HEAD_64);
194	    } else if (h_q == 128) {
195	        required_features.push_back(FwdFeatures::HEAD_128);
196	    } else {
197	        TORCH_CHECK(false, "Unsupported h_q: ", h_q);
198	    }
199	    if (d_qk == 576) {
200	        required_features.push_back(FwdFeatures::HEAD_DIM_576);
201	    } else if (d_qk == 512) {
202	        required_features.push_back(FwdFeatures::HEAD_DIM_512);
203	    } else {
204	        TORCH_CHECK(false, "Unsupported d_qk: ", d_qk);
205	    }
206	    if (attn_sink.has_value()) {
207	        required_features.push_back(FwdFeatures::ATTN_SINK);
208	    }
209	    if (have_topk_length) {
210	        required_features.push_back(FwdFeatures::TOPK_LENGTH);
211	    }
212	
213	    if (is_sm90a) {
214	        Fwd_Sm90_Impl fwd_impl;
215	        fwd_impl.run(params, required_features);
216	    } else if (is_sm100f) {
217	        if (h_q == 64) {
218	            Fwd_Sm100_Head64_Impl fwd_impl;
219	            fwd_impl.run(params, required_features);
220	        } else if (h_q == 128) {
221	            Fwd_Sm100_Head128_Small_TopK_Impl small_topk_impl;
222	            Fwd_Sm100_Head128_Impl regular_impl;
223	            bool use_small_topk_impl = false;
224	            if (
225	                (topk <= 1280 && small_topk_impl.check_if_all_features_are_supported(required_features)) ||
226	                !regular_impl.check_if_all_features_are_supported(required_features)
227	            ) {
228	                use_small_topk_impl = true;
229	            }
230	            if (use_small_topk_impl) {
231	                small_topk_impl.run(params, required_features);
232	            } else {
233	                regular_impl.run(params, required_features);
234	            }
235	        } else {
236	            TORCH_CHECK(false, "Unsupported h_q: ", h_q);
237	        }
238	    } else {
239	        TORCH_CHECK(false, "Unsupported architecture");
240	    }
241	
242	    return {out, max_logits, lse};
243	}
