61	};
62	
63	struct SparseAttnDecodeParams {
64	    int b, s_q;
65	    int h_q, h_kv;
66	    int d_qk, d_v;
67	    float sm_scale, sm_scale_div_log2;
68	    int num_blocks, page_block_size, topk;
69	    ModelType model_type;
70	
71	    cutlass::bfloat16_t* __restrict__ q;   // [b, s_q, h_q, d_qk]
72	    cutlass::bfloat16_t* __restrict__ kv;  // [num_blocks, page_block_size, d_qk]
73	    int* __restrict__ indices;   // [b, s_q, topk]
74	    int* __restrict__ topk_length;  // [b], may be nullptr
75	    float* __restrict__ attn_sink;  // [h_q], may be nullptr
76	
77	    float* __restrict__ lse;    // [b, s_q, h_q]
78	    cutlass::bfloat16_t* __restrict__ out;   // [b, s_q, h_q, d_v]
79	    
