153	
154	Every implementation should inherit from this class and implement the pure virtual functions, including:
155	- `run_`: The function that runs the implementation.
156	- `get_supported_features`: The function that returns the supported features of the implementation. You may use `DECLARE_SUPPORTED_FEATURES` to declare the supported features in a concise way.
157	
158	The dispatcher will invoke `ImplBase::run()`, which checks if all required features are supported by the implementation, and then calls `run_`.
159	*/
160	template<
161	    typename RunArgT_,
162	    typename FeatureT_
163	>
